<?php namespace App\Services\Finance; use App\Contracts\Payments\PaymentProviderInterface; use App\Data\Payments\{PaymentProviderResult,PaymentWebhookResult}; use App\Models\PaymentRecord;
class DisabledPaymentProvider implements PaymentProviderInterface{public function providerKey():string{return 'disabled';}public function isConfigured():bool{return false;}private function blocked():PaymentProviderResult{return new PaymentProviderResult(false,'Payment provider not connected yet.');}public function createPaymentIntent(PaymentRecord $payment):PaymentProviderResult{return $this->blocked();}public function capture(PaymentRecord $payment):PaymentProviderResult{return $this->blocked();}public function refund(PaymentRecord $payment,int|float|string $amount,string $reason):PaymentProviderResult{return $this->blocked();}public function parseWebhook(array $payload,array $headers=[]):PaymentWebhookResult{return new PaymentWebhookResult(false,'rejected');}}
